const Nav = ({ active, setActive }) => {
  const isMobile = useIsMobile();
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    const onScroll = () => {
      setScrolled(window.scrollY > 40);
      const offsets = NAV_LINKS.map(({ id }) => {
        const el = document.getElementById(id);
        return el ? { id, top: el.getBoundingClientRect().top } : null;
      }).filter(Boolean);
      const current = offsets.filter(o => o.top <= 80).pop();
      if (current) {
        const found = NAV_LINKS.find(n => n.id === current.id);
        if (found) setActive(found.label);
      }
    };
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, [setActive]);

  useEffect(() => {
    if (menuOpen) {
      const close = () => setMenuOpen(false);
      window.addEventListener("scroll", close, { passive: true, once: true });
    }
  }, [menuOpen]);

  const scrollTo = (id, label) => {
    setActive(label);
    setMenuOpen(false);
    const el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: "smooth", block: "start" });
  };

  return (
    <>
      <nav style={{
        position:"sticky", top:0, zIndex:200,
        background: (scrolled || menuOpen) ? "rgba(0,0,0,0.97)" : C.black,
        backdropFilter: scrolled ? "blur(12px)" : "none",
        borderBottom: "1px solid rgba(255,255,255,0.06)",
        display:"flex", justifyContent:"space-between", alignItems:"center",
        padding: isMobile ? "0 20px" : "0 56px",
        height: 56,
        transition:"background 0.3s",
      }}>
        {/* Logo */}
        <div style={{ display:"flex", alignItems:"center", gap:8, cursor:"pointer" }}
             onClick={() => scrollTo("section-hero", "Overview")}>
          <div style={{
            fontFamily:"'Barlow Condensed', sans-serif",
            fontWeight:800, fontSize: isMobile ? "0.85rem" : "1rem",
            letterSpacing:"0.3em", textTransform:"uppercase", color:C.white,
          }}>
            THE <span style={{ color:C.red }}>CREA</span>TIVE
          </div>
          {!isMobile && (
            <span style={{
              fontFamily:"'IBM Plex Mono', monospace",
              fontSize:"0.52rem", color:"rgba(255,255,255,0.2)",
              letterSpacing:"0.12em", marginLeft:6,
            }}>CR8TV</span>
          )}
        </div>

        {/* Desktop links */}
        {!isMobile && (
          <div style={{ display:"flex", gap:2 }}>
            {NAV_LINKS.map(({ label, id }) => (
              <button key={label} onClick={() => scrollTo(id, label)} style={{
                fontFamily:"'Barlow Condensed', sans-serif",
                fontSize:"0.62rem", fontWeight:700,
                letterSpacing:"0.18em", textTransform:"uppercase",
                color: active === label ? C.white : "rgba(255,255,255,0.3)",
                background:"none", border:"none", cursor:"pointer",
                padding:"6px 14px",
                borderBottom: active === label ? `2px solid ${C.red}` : "2px solid transparent",
                transition:"all 0.2s",
              }}>{label}</button>
            ))}
          </div>
        )}

        <div style={{ display:"flex", alignItems:"center", gap:16 }}>
          {!isMobile && (
            <div style={{
              fontFamily:"'IBM Plex Mono', monospace",
              fontSize:"0.55rem", color:"rgba(255,255,255,0.18)",
              letterSpacing:"0.1em",
            }}>CONFIDENTIAL · 2025</div>
          )}

          {/* Hamburger */}
          {isMobile && (
            <button onClick={() => setMenuOpen(o => !o)} style={{
              background:"none", border:"none", cursor:"pointer",
              padding:"8px 0", display:"flex", flexDirection:"column",
              gap:5, alignItems:"flex-end", width:28,
            }}>
              <span style={{
                display:"block", height:1.5, width:22, background:C.white,
                transition:"all 0.25s",
                transform: menuOpen ? "rotate(45deg) translate(0px, 6.5px)" : "none",
                transformOrigin:"center",
              }}/>
              <span style={{
                display:"block", height:1.5, width:16, background:C.white,
                transition:"all 0.2s", opacity: menuOpen ? 0 : 1,
              }}/>
              <span style={{
                display:"block", height:1.5, width:22, background:C.white,
                transition:"all 0.25s",
                transform: menuOpen ? "rotate(-45deg) translate(0px, -6.5px)" : "none",
                transformOrigin:"center",
              }}/>
            </button>
          )}
        </div>
      </nav>

      {/* Mobile drawer */}
      {isMobile && (
        <div style={{
          position:"fixed", top:56, left:0, right:0, zIndex:199,
          background:"rgba(0,0,0,0.97)",
          borderBottom: menuOpen ? "1px solid rgba(255,255,255,0.08)" : "none",
          maxHeight: menuOpen ? 480 : 0,
          overflow:"hidden",
          transition:"max-height 0.35s cubic-bezier(0.4,0,0.2,1)",
        }}>
          {NAV_LINKS.map(({ label, id }, i) => (
            <button key={label} onClick={() => scrollTo(id, label)} style={{
              display:"flex", alignItems:"center", justifyContent:"space-between",
              width:"100%", padding:"18px 24px",
              background:"none", border:"none",
              borderBottom:"1px solid rgba(255,255,255,0.05)",
              cursor:"pointer",
            }}>
              <div style={{ display:"flex", alignItems:"center", gap:16 }}>
                <span style={{
                  fontFamily:"'IBM Plex Mono', monospace",
                  fontSize:"0.58rem", color:C.red, letterSpacing:"0.1em",
                }}>0{i+1}</span>
                <span style={{
                  fontFamily:"'Barlow Condensed', sans-serif",
                  fontSize:"1rem", fontWeight:700,
                  letterSpacing:"0.18em", textTransform:"uppercase",
                  color: active === label ? C.white : "rgba(255,255,255,0.5)",
                }}>{label}</span>
              </div>
              <span style={{ color:"rgba(255,255,255,0.2)", fontSize:"0.7rem" }}>→</span>
            </button>
          ))}
          <div style={{
            padding:"16px 24px",
            fontFamily:"'IBM Plex Mono', monospace",
            fontSize:"0.55rem", color:"rgba(255,255,255,0.15)", letterSpacing:"0.1em",
          }}>CONFIDENTIAL · 2025</div>
        </div>
      )}
    </>
  );
};

