// ── STAT STRIP ────────────────────────────────────────────────────────────────
const StatStrip = () => {
  const isMobile = useIsMobile();
  const stats = [
    { target:20,    suffix:"+", label:"Years of Experience" },
    { target:10000, suffix:"+", label:"Operating Hours"     },
    { target:8,     suffix:"",  label:"Expertise Verticals" },
    { target:3,     suffix:"",  label:"Core Leadership"     },
  ];
  return (
    <div style={{
      background:C.charcoal,
      display:"grid",
      gridTemplateColumns: isMobile ? "1fr 1fr" : "repeat(4,1fr)",
      borderBottom:`1px solid rgba(255,255,255,0.06)`,
    }}>
      {stats.map((s, i) => {
        const [val, ref] = useCounter(s.target);
        const rightEdge = isMobile ? i % 2 === 1 : i === stats.length - 1;
        const bottomEdge = isMobile ? i >= 2 : false;
        return (
          <div key={i} ref={ref} style={{
            padding: isMobile ? "24px 16px" : "32px 28px",
            borderRight: rightEdge ? "none" : "1px solid rgba(255,255,255,0.06)",
            borderBottom: bottomEdge ? "none" : (isMobile && i < 2 ? "1px solid rgba(255,255,255,0.06)" : "none"),
            textAlign:"center",
          }}>
            <div style={{
              fontFamily:"'IBM Plex Mono', monospace",
              fontSize: isMobile ? "1.8rem" : "2.2rem",
              fontWeight:600, color:C.red, letterSpacing:"-0.02em", lineHeight:1,
            }}>{val.toLocaleString()}{s.suffix}</div>
            <div style={{
              fontFamily:"'Barlow Condensed', sans-serif", fontSize:"0.58rem", fontWeight:700,
              letterSpacing:"0.22em", textTransform:"uppercase",
              color:"rgba(255,255,255,0.25)", marginTop:8,
            }}>{s.label}</div>
          </div>
        );
      })}
    </div>
  );
};


