// ── CASE STUDY CARD ───────────────────────────────────────────────────────────
const CaseStudyCard = ({ img, num, tag, title, subtitle, stats, body, isMobile }) => {
  const [hov, setHov] = React.useState(false);
  return (
    <div
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      style={{
        background: C.charcoal,
        border:`1px solid ${hov ? "rgba(192,57,43,0.4)" : "rgba(255,255,255,0.06)"}`,
        borderLeft:`3px solid ${hov ? C.red : "rgba(255,255,255,0.12)"}`,
        overflow:"hidden", transition:"border-color 0.25s",
        display:"flex", flexDirection:"column",
      }}>
      {/* Image */}
      <div style={{ position:"relative", height: isMobile ? 180 : 220, overflow:"hidden" }}>
        <img src={img} alt={title} style={{
          width:"100%", height:"100%", objectFit:"cover",
          transform: hov ? "scale(1.04)" : "scale(1)", transition:"transform 0.5s ease",
        }}/>
        <div style={{
          position:"absolute", inset:0,
          background:"linear-gradient(to top, rgba(0,0,0,0.85) 0%, rgba(0,0,0,0.1) 60%)",
        }}/>
        <div style={{
          position:"absolute", bottom:16, left:16,
          display:"flex", gap:8, alignItems:"center",
        }}>
          <span style={{
            fontFamily:"'IBM Plex Mono', monospace", fontSize:"0.52rem",
            color:C.red, border:`1px solid ${C.red}`, padding:"2px 8px", letterSpacing:"0.1em",
          }}>{tag}</span>
        </div>
        <div style={{
          position:"absolute", top:12, right:12,
          fontFamily:"'IBM Plex Mono', monospace", fontSize:"0.55rem",
          color:"rgba(255,255,255,0.2)", letterSpacing:"0.08em",
        }}>{num}</div>
      </div>
      {/* Content */}
      <div style={{ padding: isMobile ? "20px" : "24px 28px", flex:1 }}>
        <div style={{
          fontFamily:"'IBM Plex Mono', monospace", fontSize:"0.58rem",
          color:"rgba(255,255,255,0.3)", letterSpacing:"0.12em", textTransform:"uppercase",
          marginBottom:6,
        }}>{subtitle}</div>
        <div style={{
          fontFamily:"'Playfair Display', serif",
          fontSize: isMobile ? "1.05rem" : "1.15rem",
          fontWeight:700, color:C.white, lineHeight:1.25, marginBottom:14,
        }}>{title}</div>
        <p style={{
          fontSize:"0.78rem", fontWeight:300,
          color:"rgba(255,255,255,0.45)", lineHeight:1.75, marginBottom:18,
        }}>{body}</p>
        {stats && (
          <div style={{ display:"flex", gap:16, flexWrap:"wrap" }}>
            {stats.map(([val, lbl], i) => (
              <div key={i}>
                <div style={{
                  fontFamily:"'IBM Plex Mono', monospace", fontSize:"0.9rem",
                  fontWeight:600, color:C.red,
                }}>{val}</div>
                <div style={{
                  fontFamily:"'Barlow Condensed', sans-serif", fontSize:"0.54rem",
                  fontWeight:700, letterSpacing:"0.16em", textTransform:"uppercase",
                  color:"rgba(255,255,255,0.22)",
                }}>{lbl}</div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

